const pipeline = (x) => x();

const importers = [
  async (path) => {
    if (!/^\.[\\/](?:apps\/demo\/src\/app(?:\/(?!\.)(?:(?:(?!(?:^|\/)\.).)*?)\/|\/|$)(?!\.)(?=.)[^/]*?\.(mdx|stories\.(js|jsx|ts|tsx)))$/.exec(path)) {
      return;
    }
  
    const pathRemainder = path.substring(20);
    return import(
      /* webpackChunkName: "[request]" */
      /* webpackInclude: /(?!.*node_modules)(?:\/apps\/demo\/src\/app(?:\/(?!\.)(?:(?:(?!(?:^|\/)\.).)*?)\/|\/|$)(?!\.)(?=.)[^/]*?\.(mdx|stories\.(js|jsx|ts|tsx)))$/ */
      './apps/demo/src/app/' + pathRemainder
    );
  }
  ,
  async (path) => {
    if (!/^\.[\\/](?:libs\/ui\/src\/lib(?:\/(?!\.)(?:(?:(?!(?:^|\/)\.).)*?)\/|\/|$)(?!\.)(?=.)[^/]*?\.(mdx|stories\.(js|jsx|ts|tsx)))$/.exec(path)) {
      return;
    }
  
    const pathRemainder = path.substring(18);
    return import(
      /* webpackChunkName: "[request]" */
      /* webpackInclude: /(?!.*node_modules)(?:\/libs\/ui\/src\/lib(?:\/(?!\.)(?:(?:(?!(?:^|\/)\.).)*?)\/|\/|$)(?!\.)(?=.)[^/]*?\.(mdx|stories\.(js|jsx|ts|tsx)))$/ */
      './libs/ui/src/lib/' + pathRemainder
    );
  }
  ,
  async (path) => {
    if (!/^\.[\\/](?:libs\/shared(?:\/(?!\.)(?:(?:(?!(?:^|\/)\.).)*?)\/|\/|$)src\/lib(?:\/(?!\.)(?:(?:(?!(?:^|\/)\.).)*?)\/|\/|$)(?!\.)(?=.)[^/]*?\.(mdx|stories\.(js|jsx|ts|tsx)))$/.exec(path)) {
      return;
    }
  
    const pathRemainder = path.substring(14);
    return import(
      /* webpackChunkName: "[request]" */
      /* webpackInclude: /(?!.*node_modules)(?:\/libs\/shared(?:\/(?!\.)(?:(?:(?!(?:^|\/)\.).)*?)\/|\/|$)src\/lib(?:\/(?!\.)(?:(?:(?!(?:^|\/)\.).)*?)\/|\/|$)(?!\.)(?=.)[^/]*?\.(mdx|stories\.(js|jsx|ts|tsx)))$/ */
      './libs/shared/' + pathRemainder
    );
  }
  
];

export async function importFn(path) {
  for (let i = 0; i < importers.length; i++) {
    const moduleExports = await pipeline(() => importers[i](path));
    if (moduleExports) {
      return moduleExports;
    }
  }
}